import{_ as e,c as t,a3 as a,o as l}from"./chunks/framework.CAwIQbWu.js";const h=JSON.parse('{"title":"记3分题","description":"","frontmatter":{},"headers":[],"relativePath":"SubjectOne/记分题/记3分题.md","filePath":"SubjectOne/记分题/记3分题.md","lastUpdated":1737264998000}'),r={name:"SubjectOne/记分题/记3分题.md"};function u(n,o,c,i,s,b){return l(),t("div",null,o[0]||(o[0]=[a('<h1 id="记3分题" tabindex="-1">记3分题 <a class="header-anchor" href="#记3分题" aria-label="Permalink to &quot;记3分题&quot;">​</a></h1><blockquote><p><strong>不按规定，扣3分。</strong></p></blockquote><blockquote><p><strong>普通倒1逆3，高速倒逆12。</strong></p></blockquote><blockquote><p><strong>高速扣分口诀：慢3占6停9倒逆12</strong></p></blockquote><h2 id="q1-以下哪种违法行为一次记3分" tabindex="-1">Q1：以下哪种违法行为一次记3分？ <a class="header-anchor" href="#q1-以下哪种违法行为一次记3分" aria-label="Permalink to &quot;Q1：以下哪种违法行为一次记3分？&quot;">​</a></h2><p><strong><u>A</u></strong>：驾驶不按规定安装机动车号牌的机动车上道路行驶的（3）<br> B：使用伪造、变造的机动车号牌（12）<br> C：饮酒后驾驶机动车的（12）<br> D：驾驶与准驾车型不符的机动车的（9）</p><p>Answer：<strong><u>A</u></strong></p><blockquote><p>违3遮9假12</p></blockquote><blockquote><p>准驾不符，扣9分</p></blockquote><blockquote><p>酒驾的，一次记12分。</p></blockquote><h2 id="_1-不按规定-违3" tabindex="-1">1. 不按规定（违3） <a class="header-anchor" href="#_1-不按规定-违3" aria-label="Permalink to &quot;1. 不按规定（违3）&quot;">​</a></h2><ul><li><strong>记3分</strong></li></ul><blockquote><p>不按规定安装机动车号牌</p></blockquote><blockquote><p><code>公路客运汽车</code>、<code>旅游客运汽车</code>、<code>危险物品运输车辆</code>未按规定年检的，一次记3分，其他车型一次记1分。</p></blockquote><h2 id="_2-插队" tabindex="-1">2. 插队 <a class="header-anchor" href="#_2-插队" aria-label="Permalink to &quot;2. 插队&quot;">​</a></h2><ul><li><strong>记3分</strong></li></ul><blockquote><p>驾驶机动车遇前方机动车停车排队或者缓慢行驶时，借道超车或者占用对面车道、穿插等候车辆的，一次记3分。</p></blockquote><h2 id="_3-超载-20-50" tabindex="-1">3. 超载[20%-50%) <a class="header-anchor" href="#_3-超载-20-50" aria-label="Permalink to &quot;3. 超载[20%-50%)&quot;">​</a></h2><ul><li><strong>记3分</strong></li></ul><blockquote><p>驾驶<code>小型汽车</code>载人超过核定人数20%未达50%的，一次记3分。</p></blockquote><h2 id="_4-打电话" tabindex="-1">4. 打电话 <a class="header-anchor" href="#_4-打电话" aria-label="Permalink to &quot;4. 打电话&quot;">​</a></h2><ul><li><strong>记3分</strong></li></ul><blockquote><p>驾驶机动车有拨打、接听手持电话等妨碍安全驾驶的行为的，一次记3分。</p></blockquote><h2 id="_5-普通逆3" tabindex="-1">5. 普通逆3 <a class="header-anchor" href="#_5-普通逆3" aria-label="Permalink to &quot;5. 普通逆3&quot;">​</a></h2><ul><li><strong>记3分</strong></li></ul><blockquote><p>驾驶机动车不按规定超车、让行，或者在高速公路、城市快速路以外的道路上逆行的，一次记3分。</p></blockquote><h2 id="_6-穿插车道" tabindex="-1">6. 穿插车道 <a class="header-anchor" href="#_6-穿插车道" aria-label="Permalink to &quot;6. 穿插车道&quot;">​</a></h2><ul><li><strong>记3分</strong></li></ul><blockquote><p>遇前方机动车停车排队或缓慢行驶时，借道超车或占用对面车道、穿插等候车辆的，一次记3分。</p></blockquote><h2 id="_7-疲劳驾驶-客9货3" tabindex="-1">7. 疲劳驾驶（客9货3） <a class="header-anchor" href="#_7-疲劳驾驶-客9货3" aria-label="Permalink to &quot;7. 疲劳驾驶（客9货3）&quot;">​</a></h2><ul><li><strong>记3分</strong></li></ul><blockquote><p>（&gt;4小时或&lt;20分钟）危险物品运输车辆</p></blockquote><blockquote><p>连续驾驶<strong>载货汽车</strong>4小时以上不停车休息活休息少于20分钟的，记3分。</p></blockquote><h2 id="_8-高速太慢" tabindex="-1">8. 高速太慢 <a class="header-anchor" href="#_8-高速太慢" aria-label="Permalink to &quot;8. 高速太慢&quot;">​</a></h2><ul><li><strong>记3分</strong></li></ul><blockquote><p>在高速公路上行驶低于规定最低时速的，一次记3分。</p></blockquote>',36)]))}const d=e(r,[["render",u]]);export{h as __pageData,d as default};
